const raw = $('Webhook').first().json.body || {};
const originalPrompt = (raw.prompt || raw.text || '').trim();
let enhanced = $input.first().json.message?.content || originalPrompt || 'a cinematic scene';
// Strip any <think>...</think> tags from qwen3 reasoning
enhanced = enhanced.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
const channelId = raw.channel || raw.channel_id || 'C0AKJ788GJK';
const userId    = raw.user_id || raw.user    || '';
const clientId  = 'n8n-vid-' + Date.now();
const seed = Math.floor(Math.random() * 1_000_000_000);

// AnimateDiff v3 SD1.5 pipeline → 16-frame MP4 via VHS_VideoCombine
// Requires: v1-5-pruned-emaonly.safetensors (checkpoint) + v3_sd15_mm.ckpt (motion model)
const workflow = {
  // 1. Load SD1.5 checkpoint
  "1": {
    "inputs": { "ckpt_name": "v1-5-pruned-emaonly.safetensors" },
    "class_type": "CheckpointLoaderSimple"
  },
  // 2. Load AnimateDiff v3 motion model
  "2": {
    "inputs": {
      "model_name": "v3_sd15_mm.ckpt",
      "beta_schedule": "sqrt_linear (AnimateDiff)",
      "model": ["1", 0]
    },
    "class_type": "ADE_AnimateDiffLoaderGen1"
  },
  // 3. Positive prompt
  "3": {
    "inputs": { "text": enhanced, "clip": ["1", 1] },
    "class_type": "CLIPTextEncode"
  },
  // 4. Negative prompt
  "4": {
    "inputs": {
      "text": "blurry, low quality, static, watermark, text, logo, deformed, morphing, distorted face, bad anatomy, extra limbs",
      "clip": ["1", 1]
    },
    "class_type": "CLIPTextEncode"
  },
  // 5. Empty latent (16 frames for ~2 sec at 8fps)
  "5": {
    "inputs": { "width": 512, "height": 512, "batch_size": 16 },
    "class_type": "EmptyLatentImage"
  },
  // 6. KSampler with AnimateDiff-patched model
  "6": {
    "inputs": {
      "seed": seed, "steps": 25, "cfg": 7.5,
      "sampler_name": "euler_ancestral", "scheduler": "normal",
      "denoise": 1.0,
      "model": ["2", 0], "positive": ["3", 0], "negative": ["4", 0],
      "latent_image": ["5", 0]
    },
    "class_type": "KSampler"
  },
  // 7. VAE Decode
  "7": {
    "inputs": { "samples": ["6", 0], "vae": ["1", 2] },
    "class_type": "VAEDecode"
  },
  // 8. Combine frames to H264 MP4 using NVENC (RTX 5070 Ti)
  "8": {
    "inputs": {
      "frame_rate": 8,
      "loop_count": 0,
      "filename_prefix": "n8n_video",
      "format": "video/h264-mp4",
      "pingpong": false,
      "save_output": true,
      "pix_fmt": "yuv420p",
      "crf": 19,
      "save_metadata": true,
      "images": ["7", 0]
    },
    "class_type": "VHS_VideoCombine"
  }
};

// Store original prompt for Slack display; enhanced is used for generation only
return [{ json: { workflow, clientId, channelId, userId, prompt: originalPrompt } }];

const http = require('http');

function httpGetComfyUI(path) {
  return new Promise((resolve, reject) => {
    const req = http.get({ host: 'host.docker.internal', port: 8188, path }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
  });
}

const promptId  = $input.first().json.prompt_id;
const maxTries  = 90; // 7.5 min max (AnimateDiff takes longer than single image)

for (let i = 0; i < maxTries; i++) {
  await new Promise(r => setTimeout(r, 5000));
  const history = await httpGetComfyUI(`/history/${promptId}`);
  const entry = history[promptId];
  if (entry?.status?.completed) {
    // VHS_VideoCombine outputs ALL files (mp4 + gif preview) under 'gifs' key
    const node = Object.values(entry.outputs || {}).find(o => o.gifs?.length || o.videos?.length || o.images?.length);
    if (node) {
      const allMedia = [...(node.gifs||[]), ...(node.videos||[]), ...(node.images||[])];
      const VIDEO_EXTS = ['mp4','webm','mkv'];
      // Prefer MP4/video first, then GIF, then anything else
      const media =
        allMedia.find(m => VIDEO_EXTS.includes((m.filename||'').split('.').pop().toLowerCase())) ||
        allMedia.find(m => (m.format||'').startsWith('video/')) ||
        allMedia.find(m => (m.filename||'').split('.').pop().toLowerCase() === 'gif') ||
        allMedia[0];
      if (!media) continue;
      const buildData = $('Build ComfyUI Payload').first().json;
      const ext = (media.filename || '').split('.').pop().toLowerCase();
      const fmtField = (media.format || '');
      const mediaType = (VIDEO_EXTS.includes(ext) || fmtField.startsWith('video/')) ? 'video'
                      : (ext === 'gif' ? 'gif' : 'image');
      return [{ json: {
        promptId,
        filename:  media.filename,
        subfolder: media.subfolder || '',
        type:      media.type || 'output',
        channelId: buildData.channelId,
        userId:    buildData.userId,
        prompt:    buildData.prompt,
        mediaType
      }}];
    }
  }
}
throw new Error('ComfyUI generation timed out after 7.5 minutes');

const https = require('https');
const http = require('http');

// JSON-body Slack API call (for chat.postMessage, files.completeUploadExternal)
function slackApi(method, body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const req = https.request({
      method: 'POST', hostname: 'slack.com', path: `/api/${method}`,
      headers: {
        'Authorization': `Bearer ${$env.SLACK_BOT_TOKEN}`,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(data)
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

// Form-encoded Slack API call (required for files.getUploadURLExternal)
function slackFormApi(method, params) {
  return new Promise((resolve, reject) => {
    const formBody = Object.keys(params)
      .map(k => encodeURIComponent(k) + '=' + encodeURIComponent(String(params[k])))
      .join('&');
    const req = https.request({
      method: 'POST', hostname: 'slack.com', path: `/api/${method}`,
      headers: {
        'Authorization': `Bearer ${$env.SLACK_BOT_TOKEN}`,
        'Content-Type': 'application/x-www-form-urlencoded',
        'Content-Length': Buffer.byteLength(formBody)
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
    req.write(formBody);
    req.end();
  });
}

function uploadFileToBucket(uploadUrl, fileData) {
  return new Promise((resolve, reject) => {
    // Parse URL manually — require('url').URL not available in sandbox
    const match = uploadUrl.match(/^https?:\/\/([^/?#]+)(.*)/);
    if (!match) { reject(new Error('Bad upload URL: ' + uploadUrl.slice(0,80))); return; }
    const [, hostname, path] = match;
    const req = https.request({
      method: 'POST', hostname, path,
      headers: { 'Content-Type': 'application/octet-stream', 'Content-Length': fileData.length }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks).toString()));
    });
    req.on('error', reject);
    req.write(fileData);
    req.end();
  });
}

function downloadFromComfyUI(filename, subfolder, type) {
  return new Promise((resolve, reject) => {
    const p = `/view?filename=${encodeURIComponent(filename)}&subfolder=${encodeURIComponent(subfolder)}&type=${type}`;
    const req = http.get({ host: 'host.docker.internal', port: 8188, path: p }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks)));
    });
    req.on('error', reject);
  });
}

const ctx = $input.first().json;
const channelId = ctx.channelId || 'C0AKJ788GJK';
const prompt = ctx.prompt || '';
const mediaType = ctx.mediaType || 'video';

if (mediaType === 'video') {
  // Download the MP4 from ComfyUI
  const fileData = await downloadFromComfyUI(ctx.filename, ctx.subfolder || '', ctx.type || 'output');
  if (!fileData || fileData.length === 0) {
    throw new Error(`ComfyUI download failed or empty for: ${ctx.filename}`);
  }
  const filename = ctx.filename || 'video.mp4';
  const title = `Video: ${prompt.slice(0, 80)}`;
  const comment = `:film_frames: *Video Generated*\n*Prompt:* ${prompt.slice(0, 200)}\n_AnimateDiff v3 SD1.5 16-frame MP4 on RTX 5070 Ti \u00b7 ${new Date().toLocaleTimeString()}_`;

  // Step 1: Get upload URL — requires form-encoded body (NOT JSON)
  const urlResp = await slackFormApi('files.getUploadURLExternal', {
    filename,
    length: fileData.length
  });
  if (!urlResp.ok) throw new Error(`getUploadURLExternal failed: ${urlResp.error || JSON.stringify(urlResp)}`);

  // Step 2: Upload file bytes to Slack's presigned storage URL
  await uploadFileToBucket(urlResp.upload_url, fileData);

  // Step 3: Complete upload — try with channel_id to share directly in channel
  let completeResp = await slackApi('files.completeUploadExternal', {
    files: [{ id: urlResp.file_id, title }],
    channel_id: channelId,
    initial_comment: comment
  });

  if (completeResp.ok) {
    // File uploaded and shared to channel directly — done!
    return [{ json: { ok: true, channel: channelId, file_id: completeResp.files?.[0]?.id } }];
  }

  // Step 4: If bot not in channel, complete without channel_id then post a message with the link
  if (completeResp.error === 'not_in_channel' || completeResp.error === 'channel_not_found') {
    completeResp = await slackApi('files.completeUploadExternal', {
      files: [{ id: urlResp.file_id, title }]
    });
    if (!completeResp.ok) throw new Error(`completeUploadExternal failed: ${completeResp.error}`);

    const fileInfo = completeResp.files?.[0];
    const fileUrl = fileInfo?.permalink || fileInfo?.url_private || '';

    const msgResult = await slackApi('chat.postMessage', {
      channel: channelId,
      text: comment + (fileUrl ? `\n<${fileUrl}|\u25b6 Watch / Download Video>` : '')
    });
    if (!msgResult.ok) throw new Error(`chat.postMessage failed: ${msgResult.error}`);
    return [{ json: { ok: true, ts: msgResult.ts, channel: msgResult.channel, channelId } }];
  }

  throw new Error(`completeUploadExternal failed: ${completeResp.error || JSON.stringify(completeResp)}`);

} else {
  // Fallback for GIF/image: use image block with ComfyUI preview URL
  const ngrokBase = ($env.WEBHOOK_URL || '').replace(/\/$/, '');
  const imageUrl = `${ngrokBase}/webhook/preview-comfyui?filename=${encodeURIComponent(ctx.filename)}&subfolder=${encodeURIComponent(ctx.subfolder || '')}&type=${ctx.type || 'output'}`;
  const titleText = ':film_frames: Video Generated';
  const blocks = [
    { type: 'header', text: { type: 'plain_text', text: titleText } },
    { type: 'section', text: { type: 'mrkdwn', text: `*Prompt:* ${prompt.slice(0, 200)}` } },
    { type: 'image', image_url: imageUrl, alt_text: 'Generated output' },
    { type: 'context', elements: [{ type: 'mrkdwn', text: `_AnimateDiff v3 on RTX 5070 Ti \u00b7 ${new Date().toLocaleTimeString()}_` }] }
  ];
  const result = await slackApi('chat.postMessage', {
    channel: channelId,
    text: `${titleText}: ${prompt.slice(0, 80)}`,
    blocks
  });
  if (!result.ok) throw new Error(`Slack post failed: ${result.error}`);
  return [{ json: { ok: true, ts: result.ts, channel: result.channel, channelId } }];
}

// Restore context from Poll Until Done node (HTTP Request dropped it)
const poll = $('Poll Until Done').first().json;
const item = $input.first();
return [{
  json: {
    channelId: poll.channelId || '',
    filename: poll.filename || 'file',
    prompt: poll.prompt || '',
    uploadComment: poll.uploadComment || '{}'
  },
  binary: item.binary
}];
